package com.agent.tool.engine.api.impl;  import com.agent.tool.engine.enums.ExecutorType; import com.agent.tool.engine.enums.SideEffect; import com.agent.tool.engine.model.ToolMeta; import com.agent.tool.engine.model.ToolSchema; import org.junit.jupiter.api.DisplayName; import org.junit.jupiter.api.Test;  import java.util.List;  import static org.assertj.core.api.Assertions.assertThat; import static org.assertj.core.api.Assertions.assertThatThrownBy;  /**  * {@link ToolRegistryImpl} 单元测试。  */ class ToolRegistryImplTest {      private final ToolRegistryImpl registry = new ToolRegistryImpl();      @Test     @DisplayName("toolId 缺失时: register 自动生成 tool-N")     void should_GenerateToolId_When_NotProvided() {         ToolMeta meta = new ToolMeta(null, "auto_name", ExecutorType.GENERAL, SideEffect.NONE);          String toolId = registry.register(meta, new ToolSchema(List.of("q")), null);          assertThat(toolId).startsWith("tool-");         assertThat(meta.getToolId()).isEqualTo(toolId);         assertThat(registry.size()).isEqualTo(1);     }      @Test     @DisplayName("注册后: findMeta 返回元数据")     void should_FindMeta_When_Registered() {         ToolMeta meta = new ToolMeta("tool_db", "db_query", ExecutorType.PROXY, SideEffect.REVERSIBLE);         registry.register(meta, null, null);          ToolMeta found = registry.findMeta("tool_db");          assertThat(found).isNotNull();         assertThat(found.getName()).isEqualTo("db_query");         assertThat(found.getExecutorType()).isEqualTo(ExecutorType.PROXY);     }      @Test     @DisplayName("注册后: findInputSchema 返回输入 schema")     void should_FindInputSchema_When_Registered() {         ToolMeta meta = new ToolMeta("tool_v", "validate", ExecutorType.GENERAL, SideEffect.NONE);         ToolSchema schema = new ToolSchema(List.of("orderId", "tenantId"));         registry.register(meta, schema, null);          ToolSchema found = registry.findInputSchema("tool_v");          assertThat(found).isNotNull();         assertThat(found.getRequiredFields()).containsExactly("orderId", "tenantId");     }      @Test     @DisplayName("未注册或空 toolId: findMeta / findInputSchema 返回 null")     void should_ReturnNull_When_NotFound() {         assertThat(registry.findMeta("not_exist")).isNull();         assertThat(registry.findInputSchema("not_exist")).isNull();         assertThat(registry.findMeta(null)).isNull();         assertThat(registry.findInputSchema("  ")).isNull();     }      @Test     @DisplayName("meta 为 null: register 抛 IllegalArgumentException")     void should_Throw_When_MetaIsNull() {         assertThatThrownBy(() -> registry.register(null, null, null))                 .isInstanceOf(IllegalArgumentException.class)                 .hasMessageContaining("meta");     }      @Test     @DisplayName("unregister 已注册工具: 返回 true 且 findMeta 返回 null")     void should_Unregister_When_Exists() {         ToolMeta meta = new ToolMeta("tool_del", "del", ExecutorType.GENERAL, SideEffect.NONE);         registry.register(meta, new ToolSchema(List.of()), null);          boolean removed = registry.unregister("tool_del");          assertThat(removed).isTrue();         assertThat(registry.findMeta("tool_del")).isNull();         assertThat(registry.findInputSchema("tool_del")).isNull();         assertThat(registry.size()).isZero();     } }